mapper.update:
/* wms-outbound-DlvryWblManager-sql-oracle.xml.updateDlvryWblInfo 택배사 운송장번호 대역 사용 */

	SELECT COALESCE(WBLCURRNO, WBLFROMNO) AS WBLCURRNO
	FROM TWORK_MST_DLVRYCORP_WBL
	WHERE CTKEY = #{ctkey}
	AND OWKEY = #{owkey}
	AND DLVRYCORPCD = #{dlvryCorpCd}
	AND ISSUSEQ = #{issuSeq}
	AND WBLFROMNO = #{wblFromNo}
	AND WBLTONO = #{wblToNo}


UPDATE TWORK_MST_DLVRYCORP_WBL
SET WBLCURRNO = CAST(COALESCE(WBLCURRNO, WBLFROMNO) AS NUMERIC) + #{okCnt}
	,UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND DLVRYCORPCD = #{dlvryCorpCd}
AND ISSUSEQ = #{issuSeq}
